const https = require('https');
const http = require('http');
const { URL } = require('url');
const { Agent } = require('https');

// Allowlist of domains
const ALLOWED_DOMAINS = [
  'twitter.com',
  'facebook.com',
  'linkedin.com',
  'pinterest.com',
  'reddit.com',
  'youtube.com',
  'instagram.com',
  'tiktok.com',
  'github.com',
  'medium.com',
  'wikipedia.org',
  'news.ycombinator.com'
];

// Private IP ranges
const PRIVATE_IP_RANGES = [
  /^127\./,
  /^10\./,
  /^172\.(1[6-9]|2[0-9]|3[0-1])\./,
  /^192\.168\./,
  /^169\.254\./,
  /^::1$/,
  /^fe80:/,
  /^fc00:/,
  /^fd00:/,
  /^::ffff:127\./,
  /^::ffff:10\./,
  /^::ffff:172\.(1[6-9]|2[0-9]|3[0-1])\./,
  /^::ffff:192\.168\./,
  /^::ffff:169\.254\./
];

// Custom agent with timeout and keep-alive
const agent = new Agent({
  keepAlive: true,
  keepAliveMsecs: 1000,
  timeout: 5000,
  maxSockets: 50,
  maxFreeSockets: 10,
  freeSocketTimeout: 30000
});

// Check if URL is allowed
function isAllowedUrl(urlString) {
  try {
    const url = new URL(urlString);
    const hostname = url.hostname;
    
    // Check if domain is in allowlist
    const isAllowedDomain = ALLOWED_DOMAINS.some(domain => 
      hostname === domain || hostname.endsWith('.' + domain)
    );
    
    if (!isAllowedDomain) {
      return false;
    }
    
    // Check for private IP ranges
    const ip = require('ip');
    if (ip.isPrivate(hostname) || PRIVATE_IP_RANGES.some(pattern => pattern.test(hostname))) {
      return false;
    }
    
    return true;
  } catch (error) {
    return false;
  }
}

// Fetch metadata from URL
async function fetchMetadata(urlString) {
  if (!isAllowedUrl(urlString)) {
    throw new Error('URL not allowed');
  }
  
  return new Promise((resolve, reject) => {
    const url = new URL(urlString);
    const options = {
      hostname: url.hostname,
      port: url.port,
      path: url.pathname + url.search,
      method: 'GET',
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; LinkShareBot/1.0)',
        'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
        'Accept-Language': 'en-US,en;q=0.5',
        'Accept-Encoding': 'gzip, deflate',
        'Connection': 'keep-alive',
      },
      agent: agent,
      timeout: 5000,
      maxRedirects: 3,
      rejectUnauthorized: true
    };
    
    const protocol = url.protocol === 'https:' ? https : http;
    
    const req = protocol.request(options, (res) => {
      let data = '';
      let redirectCount = 0;
      
      // Handle redirects
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        redirectCount++;
        const redirectUrl = new URL(res.headers.location, urlString);
        
        if (redirectCount > options.maxRedirects) {
          reject(new Error('Too many redirects'));
          return;
        }
        
        // Validate redirect URL
        if (!isAllowedUrl(redirectUrl.toString())) {
          reject(new Error('Redirect URL not allowed'));
          return;
        }
        
        // Make new request to redirect URL
        fetchMetadata(redirectUrl.toString())
          .then(resolve)
          .catch(reject);
        return;
      }
      
      // Handle response
      res.on('data', (chunk) => {
        data += chunk;
      });
      
      res.on('end', () => {
        try {
          const metadata = parseHtml(data);
          resolve(metadata);
        } catch (error) {
          reject(error);
        }
      });
    });
    
    req.on('error', (error) => {
      reject(error);
    });
    
    req.on('timeout', () => {
      req.destroy();
      reject(new Error('Request timeout'));
    });
    
    req.end();
  });
}

// Parse HTML for metadata
function parseHtml(html) {
  const metadata = {};
  
  // Extract title
  const titleMatch = html.match(/<title[^>]*>(.*?)<\/title>/i);
  if (titleMatch && titleMatch[1]) {
    metadata.title = titleMatch[1].trim();
  }
  
  // Extract Open Graph tags
  const ogTags = {
    'og:title': 'title',
    'og:description': 'description',
    'og:image': 'image',
    'og:url': 'url',
    'og:type': 'type',
    'og:site_name': 'site_name'
  };
  
  for (const [ogKey, metaKey] of Object.entries(ogTags)) {
    const match = html.match(new RegExp(`<meta[^>]*property="${ogKey}"[^>]*content="(.*?)"`, 'i'));
    if (match && match[1]) {
      metadata[metaKey] = match[1].trim();
    }
  }
  
  // Extract description meta tag
  if (!metadata.description) {
    const descMatch = html.match(/<meta[^>]*name="description"[^>]*content="(.*?)"[^>]*>/i);
    if (descMatch && descMatch[1]) {
      metadata.description = descMatch[1].trim();
    }
  }
  
  // Extract canonical URL
  const canonicalMatch = html.match(/<link[^>]*rel="canonical"[^>]*href="(.*?)"[^>]*>/i);
  if (canonicalMatch && canonicalMatch[1]) {
    metadata.canonical = canonicalMatch[1].trim();
  }
  
  // Fallback to title if no title found
  if (!metadata.title) {
    metadata.title = 'Untitled';
  }
  
  // Fallback to description if no description found
  if (!metadata.description) {
    metadata.description = '';
  }
  
  return metadata;
}

// Main function for Cloud Function
exports.fetchLinkMetadata = async (req, res) => {
  try {
    const url = req.body.url;
    
    if (!url) {
      return res.status(400).json({ error: 'URL is required' });
    }
    
    const metadata = await fetchMetadata(url);
    res.status(200).json({ metadata });
  } catch (error) {
    console.error('Metadata fetch error:', error);
    res.status(500).json({ error: 'Failed to fetch metadata' });
  }
};